def to_code_count(cards: list[dict[str, int]] | None) -> dict[str, int]:
    if not cards:
        return {}
    result: dict[str, int] = {}
    for row in cards:
        code = str(row["code"]).strip()
        count = int(row["count"])
        if not code or count <= 0:
            continue
        result[code] = result.get(code, 0) + count
    return result


def format_cards(cards: dict[str, int] | None) -> str:
    if not cards:
        return "null"
    return repr(cards)


def main() -> None:
    tournaments = json.loads(TOURNAMENTS_PATH.read_text(encoding="utf-8"))
    canonical_map = build_canonical_map(CARDDB_DIR)

    rows: list[str] = []
    date_counts: Counter[str] = Counter()

    for tournament in tournaments:
        date = str(tournament["date"])
        player_count = int(tournament["playerCount"])
        tid = str(tournament["tid"])
        for player in tournament.get("players", []):
            deck_code = player.get("deck_code")
            raw_cards = raw_deck_cards.get(deck_code)
            if raw_cards is None:
                card_field = "null"
            else:
                normalized = normalize_deck(to_code_count(raw_cards), canonical_map)
                card_field = format_cards(normalized)
            row = "\t".join(
                [
                    date,
                    str(player.get("class", "")),
                    str(player.get("rank", "")),
                    str(player_count),
                    str(deck_code or ""),
                    tid,
                    card_field,
                ]
            )
            rows.append(row)
            date_counts[date] += 1

    with OUTPUT_PATH.open("a", encoding="utf-8") as fp:
        if rows:
            fp.write("\n")
            fp.write("\n".join(rows))

    print(f"added_records\t{len(rows)}")
    for date, count in sorted(date_counts.items()):
        print(f"{date}\t{count}")


if __name__ == "__main__":
    main()
